import tkinter as tk
from tkinter.filedialog import askopenfile
from tkinter import messagebox
from PIL import Image, ImageTk
import os

# ——— Парсинг RGB-строки (как в JS: parseRGBString) ———
def parse_rgb_string(text):
    """Принимает строку с числами через пробел, возвращает плоский список [R,G,B,...]"""
    parts = text.strip().split()
    flat = []
    for i in range(0, len(parts) - 2, 3):
        try:
            r = int(parts[i])
            g = int(parts[i + 1])
            b = int(parts[i + 2])
            flat.extend([r, g, b])
        except ValueError:
            continue
    return flat

